using System;

struct Point {
    public double X, Y;
    public Point(double x, double y) { X = x; Y = y; }
    public double Distance(Point other) =>
        Math.Sqrt(Math.Pow(X - other.X, 2) + Math.Pow(Y - other.Y, 2));
}

class Program {
    static void Main() {
        var p1 = new Point(0, 0);
        var p2 = new Point(3, 4);
        Console.WriteLine(p1.Distance(p2));
    }
}

